import React, { useLayoutEffect, useState } from "react";
import { getAllEquipmentInfoData } from "../../../../../api";
import { useSetRecoilState } from "recoil";
import { Notification } from "../../../../../modules/global/global-states";
import axios from "axios";

type equipmentInfo = {
  id: number;
  serial: string;
  assetNumber: string;
  healthScore: string;
  brand: string;
  model: string;
  hospital: string;
};

export function useEquipmentInfoRecordTableHooks() {
  const setNotification = useSetRecoilState(Notification);
  const [equipmentInfoData, setEquipmentInfoData] = useState<equipmentInfo[]>(
    []
  );

  useLayoutEffect(() => {
    getAllEquipmentInfoData()
      .then((res) => {
        setEquipmentInfoData(res);
      })
      .catch((err) => {
        setNotification({
          title: "Error fetching Equipment Info Record data",
          message: JSON.stringify(err),
          level: 2,
        });
      });
  }, [setNotification]);

  return equipmentInfoData;
}
